import {
  Component,
  input,
  model,
  output,
  signal,
  ViewChild,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { DialogModule } from 'primeng/dialog';
import { ButtonModule } from 'primeng/button';
import { StepperComponent } from '../stepper/stepper.component';
import { Step } from '../../models';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-wizard',
  imports: [
    CommonModule,
    DialogModule,
    ButtonModule,
    StepperComponent,
    TranslatePipe,
  ],
  templateUrl: './wizard.component.html',
  styleUrls: ['./wizard.component.scss'],
})
export class WizardComponent {
  @ViewChild(StepperComponent) stepper?: StepperComponent;

  // Input properties
  readonly steps = input<Step[]>([]);
  readonly visible = model<boolean>(false);
  readonly header = input('Wizard');
  readonly linearProgression = input(true);
  readonly showFooterButtons = input(true);
  readonly closeOnEscape = input(true);
  readonly useWizardButtonsOnly = input(false);
  readonly showSteps = input(true);
  readonly contentOnly = input(false);
  readonly loading = model<boolean>(false);

  // Output properties
  readonly onCancel = output<void>();
  readonly complete = output<Step[]>();
  readonly stepChange = output<number>();

  // Component state
  readonly currentStep = model<number>(1);
  readonly isValidating = signal(false);

  hideDialog(): void {
    this.visible.set(false);
  }

  cancelWizard(): void {
    this.onCancel.emit();
    this.hideDialog();
  }

  onComplete(): void {
    // Verify steps exist
    if (this.steps().length === 0) {
      console.warn('No steps defined in the wizard');
      return;
    }

    this.complete.emit(this.steps());
    this.hideDialog();
  }

  test() {
    this.loading.set(true);
  }

  onStepComplete(): void {
    this.onComplete();
  }

  onStepChange(step: number): void {
    this.currentStep.set(step);
    this.stepChange.emit(step);
  }

  isLastStep(): boolean {
    if (this.steps().length === 0) return true;
    return this.currentStep() === Math.max(...this.steps().map((s) => s.value));
  }

  isFirstStep(): boolean {
    if (this.steps().length === 0) return true;
    return this.currentStep() === Math.min(...this.steps().map((s) => s.value));
  }

  // Methods for footer buttons
  async goNext(): Promise<void> {
    const currentStepData = this.steps().find(
      (s) => s.value === this.currentStep(),
    );

    if (currentStepData?.validate) {
      this.isValidating.set(true);
      try {
        const validationResult = currentStepData.validate();
        const isValid =
          validationResult instanceof Promise
            ? await validationResult
            : validationResult;
        if (isValid) {
          this.stepper?.goNext();
        }
      } finally {
        this.isValidating.set(false);
      }
    } else {
      this.stepper?.goNext();
    }
  }

  canGoNext(): boolean {
    // Check if we can go to next step
    const currentStepData = this.steps().find(
      (s) => s.value === this.currentStep(),
    );

    // Add the validation check to the existing conditions
    return !this.isLastStep() && !(currentStepData?.disableNext ?? false);
    // Note: The actual form validation is handled by the disableNext property,
    // which should be updated by the form's validity state
  }

  goBack(): void {
    this.stepper?.goBack();
  }

  canFinish(): boolean {
    return this.isLastStep() && (this.stepper?.canFinish() ?? false);
  }

  getCurrentStep(): Step | undefined {
    return this.steps().find((s) => s.value === this.currentStep());
  }
}
